/**
 * AURA TRADING DESK — useCompute Hook
 * Polls compute endpoints: jobs, workers, usage, credits, tiers.
 * Exports: { jobs, workers, usage, credits, tiers, subscription,
 *            submitJob, cancelJob, addCredits, configureAutoReload, refetch, loading }
 */
import { useState, useEffect, useCallback } from 'react';
import { getApiBase } from '../utils/platform';

function authHeaders() {
  const token = localStorage.getItem('aura_token');
  return token ? { Authorization: `Bearer ${token}` } : {};
}

export default function useCompute(pollInterval = 15000) {
  const [jobs, setJobs] = useState([]);
  const [workers, setWorkers] = useState([]);
  const [usage, setUsage] = useState(null);
  const [credits, setCredits] = useState(null);
  const [tiers, setTiers] = useState([]);
  const [subscription, setSubscription] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchAll = useCallback(async () => {
    try {
      const [jobsRes, workersRes, usageRes, creditsRes, tiersRes] = await Promise.all([
        fetch(`${getApiBase()}/compute/jobs`, { headers: authHeaders() }),
        fetch(`${getApiBase()}/compute/workers`, { headers: authHeaders() }),
        fetch(`${getApiBase()}/compute/usage`, { headers: authHeaders() }),
        fetch(`${getApiBase()}/compute/credits`, { headers: authHeaders() }),
        fetch(`${getApiBase()}/compute/tiers`),
      ]);

      const [jobsData, workersData, usageData, creditsData, tiersData] = await Promise.all([
        jobsRes.ok ? jobsRes.json() : { jobs: [] },
        workersRes.ok ? workersRes.json() : { workers: [] },
        usageRes.ok ? usageRes.json() : {},
        creditsRes.ok ? creditsRes.json() : {},
        tiersRes.ok ? tiersRes.json() : { tiers: [] },
      ]);

      setJobs(jobsData.jobs || []);
      setWorkers(workersData.workers || []);
      setUsage(usageData);
      setSubscription(usageData.subscription || null);
      setCredits(creditsData);
      setTiers(tiersData.tiers || []);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAll();
    if (pollInterval > 0) {
      const iv = setInterval(fetchAll, pollInterval);
      return () => clearInterval(iv);
    }
  }, [fetchAll, pollInterval]);

  const submitJob = useCallback(async (jobType, params = {}, workerType = 'cloud') => {
    const res = await fetch(`${getApiBase()}/compute/jobs`, {
      method: 'POST',
      headers: { ...authHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ job_type: jobType, params, worker_type: workerType }),
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.detail || 'Submit failed');
    fetchAll();
    return data;
  }, [fetchAll]);

  const cancelJob = useCallback(async (jobId) => {
    const res = await fetch(`${getApiBase()}/compute/jobs/${jobId}`, {
      method: 'DELETE',
      headers: authHeaders(),
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.detail || 'Cancel failed');
    fetchAll();
    return data;
  }, [fetchAll]);

  const addCredits = useCallback(async (hours) => {
    const res = await fetch(`${getApiBase()}/compute/credits/add`, {
      method: 'POST',
      headers: { ...authHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ hours }),
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.detail || 'Add credits failed');
    fetchAll(); // refresh credits display immediately
    return data;
  }, [fetchAll]);

  const configureAutoReload = useCallback(async (enabled, threshold, amount) => {
    const res = await fetch(`${getApiBase()}/compute/credits/auto-reload`, {
      method: 'POST',
      headers: { ...authHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({ enabled, threshold, amount }),
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.detail || 'Configure failed');
    fetchAll();
    return data;
  }, [fetchAll]);

  return {
    jobs,
    workers,
    usage,
    credits,
    tiers,
    subscription,
    submitJob,
    cancelJob,
    addCredits,
    configureAutoReload,
    refetch: fetchAll,
    loading,
    error,
  };
}
