import { useState, useEffect } from 'react';
import useCompute from '../hooks/useCompute';
import useRegions from '../hooks/useRegions';
import AuraLogo from '@/components/AuraLogo';
import { getApiBase } from '@/utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import s from './ComputeDashboardPage.module.css';

import { tokens } from '../styles/tokens';
const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

function authHeaders() {
  const token = localStorage.getItem('aura_token');
  return token ? { Authorization: `Bearer ${token}` } : {};
}

/* -- helpers ------------------------------------------------------------ */

function pct(used, limit) {
  if (!limit || limit <= 0 || limit === -1) return 0;
  return Math.min(100, (used / limit) * 100);
}

function barColor(p) {
  if (p >= 90) return C.red;
  if (p >= 75) return C.amber;
  return C.green;
}

function formatDate(iso) {
  if (!iso) return '--';
  const d = new Date(iso);
  if (isNaN(d)) return iso;
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function formatTime(iso) {
  if (!iso) return '--';
  const d = new Date(iso);
  if (isNaN(d)) return iso;
  return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
}

function relTime(iso) {
  if (!iso) return '--';
  const d = new Date(iso);
  const now = new Date();
  const sec = Math.floor((now - d) / 1000);
  if (sec < 60) return 'just now';
  if (sec < 3600) return `${Math.floor(sec / 60)}m ago`;
  if (sec < 86400) return `${Math.floor(sec / 3600)}h ago`;
  return `${Math.floor(sec / 86400)}d ago`;
}

const TIER_COLORS = {
  local: C.textSecondary,
  cloud_starter: C.blue,
  cloud_pro: C.purple,
  cloud_dedicated: C.amber,
};

const STATUS_COLORS = {
  queued: C.amber,
  running: C.blue,
  completed: C.green,
  failed: C.red,
  canceled: C.textSecondary,
  online: C.green,
  offline: C.textSecondary,
  busy: C.amber,
  draining: C.red,
};

/* -- sub-components ----------------------------------------------------- */

function StatusBadge({ status }) {
  const color = STATUS_COLORS[(status || '').toLowerCase()] || C.textSecondary;
  return (
    <span className={s.statusBadge} style={{ background: color }}>
      {status || 'unknown'}
    </span>
  );
}

function TierBadge({ tier }) {
  const color = TIER_COLORS[(tier || '').toLowerCase()] || C.textSecondary;
  const label = tier ? tier.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()) : 'LOCAL';
  return (
    <span className={s.tierBadge} style={{ background: color }}>
      {label}
    </span>
  );
}

function Card({ children, style, id }) {
  return (
    <div className={s.card} style={style} id={id}>
      {children}
    </div>
  );
}

function SectionHeader({ children }) {
  return (
    <div className={s.sectionHeader}>
      {children}
    </div>
  );
}

function Btn({ children, onClick, variant = 'primary', disabled, style: sx }) {
  const variantClass = {
    primary: s.btnPrimary,
    secondary: s.btnSecondary,
    danger: s.btnDanger,
    ghost: s.btnGhost,
    green: s.btnGreen,
  }[variant] || s.btnPrimary;

  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={variantClass}
      style={sx}
    >
      {children}
    </button>
  );
}

/* -- Toast -------------------------------------------------------------- */

function Toast({ toast }) {
  if (!toast) return null;
  const color = toast.type === 'success' ? C.green : toast.type === 'error' ? C.red : C.amber;
  return (
    <div className={s.toast} style={{
      background: `${color}15`, border: `1px solid ${color}40`, color,
    }}>
      {toast.message}
    </div>
  );
}

/* -- Submit Job Modal --------------------------------------------------- */

function SubmitJobModal({ open, onClose, onSubmit, loading, regions: regionsList }) {
  const [jobType, setJobType] = useState('backtest');
  const [workerType, setWorkerType] = useState('cloud');
  const [region, setRegion] = useState('us');
  const [strategy, setStrategy] = useState('all');
  const [workers, setWorkers] = useState(16);

  if (!open) return null;

  const estHours = (workers * 0.25).toFixed(1);

  const handleSubmit = () => {
    onSubmit(jobType, { region, strategy, workers: Number(workers) }, workerType);
  };

  return (
    <div onClick={onClose} className={s.modalOverlay}>
      <div onClick={(e) => e.stopPropagation()} className={s.modalContent}>
        <div className={s.modalTitle}>Submit New Job</div>

        {/* Job Type */}
        <div className={s.formGroup}>
          <label className={s.formLabel}>Job Type</label>
          <select value={jobType} onChange={(e) => setJobType(e.target.value)} className={s.formSelect}>
            <option value="backtest">Backtest</option>
            <option value="optimize">Optimize</option>
            <option value="ml_train">ML Train</option>
            <option value="signal_gen">Signal Generation</option>
          </select>
        </div>

        {/* Region + Strategy */}
        <div className={`${s.flexRow} ${s.formGroup}`}>
          <div className={s.flexCol}>
            <label className={s.formLabel}>Region</label>
            <select value={region} onChange={(e) => setRegion(e.target.value)} className={s.formSelect}>
              {(regionsList || []).map(r => (
                <option key={r.key} value={r.key}>{r.label}</option>
              ))}
            </select>
          </div>
          <div className={s.flexCol}>
            <label className={s.formLabel}>Strategy</label>
            <select value={strategy} onChange={(e) => setStrategy(e.target.value)} className={s.formSelect}>
              <option value="all">All Strategies</option>
              <option value="long_only">Long Only</option>
              <option value="short_only">Short Only</option>
            </select>
          </div>
        </div>

        {/* Workers slider */}
        <div className={s.formGroup}>
          <label className={s.formLabel}>Workers: {workers}</label>
          <input
            type="range" min={1} max={64} value={workers}
            onChange={(e) => setWorkers(parseInt(e.target.value))}
            className={s.rangeSlider}
          />
          <div className={s.rangeLabels}>
            <span>1</span>
            <span>64</span>
          </div>
        </div>

        {/* Worker Type */}
        <div className={s.formGroupLg}>
          <label className={s.formLabel}>Target</label>
          <div className={s.flexRow}>
            {['cloud', 'local'].map((t) => (
              <label key={t} className={s.radioLabel} style={{
                color: workerType === t ? C.textPrimary : C.textSecondary,
              }}>
                <input
                  type="radio" name="workerType" value={t}
                  checked={workerType === t}
                  onChange={() => setWorkerType(t)}
                  className={s.radioInput}
                />
                {t === 'cloud' ? 'Cloud' : 'My Hardware'}
              </label>
            ))}
          </div>
        </div>

        {/* Est compute hours */}
        <div className={s.estimateBox}>
          <span className={s.estimateLabel}>Est. compute-hours</span>
          <span className={s.estimateValue}>~{estHours} hrs</span>
        </div>

        {/* Actions */}
        <div className={s.flexRowEnd}>
          <Btn variant="secondary" onClick={onClose}>Cancel</Btn>
          <Btn variant="green" onClick={handleSubmit} disabled={loading}>
            {loading ? 'Submitting...' : 'Submit Job'}
          </Btn>
        </div>
      </div>
    </div>
  );
}

/* -- Register Worker Modal ---------------------------------------------- */

function RegisterWorkerModal({ open, onClose, onRegister, loading }) {
  const [name, setName] = useState('');
  const [host, setHost] = useState('');
  const [cpuCount, setCpuCount] = useState(8);
  const [memoryGb, setMemoryGb] = useState(16);
  const [gpu, setGpu] = useState('');

  if (!open) return null;

  const handleRegister = async () => {
    const res = await fetch(`${getApiBase()}/compute/workers/register`, {
      method: 'POST',
      headers: { ...authHeaders(), 'Content-Type': 'application/json' },
      body: JSON.stringify({
        worker_name: name,
        host,
        cpu_count: Number(cpuCount),
        memory_gb: Number(memoryGb),
        gpu: gpu || null,
      }),
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.detail || 'Registration failed');
    onRegister(data);
  };

  return (
    <div onClick={onClose} className={s.modalOverlay}>
      <div onClick={(e) => e.stopPropagation()} className={s.modalContentNarrow}>
        <div className={s.modalTitle}>Register Local Worker</div>

        {[
          { label: 'Worker Name', value: name, onChange: setName, placeholder: 'My-Desktop' },
          { label: 'Host', value: host, onChange: setHost, placeholder: '192.168.1.100:8080' },
        ].map(({ label, value, onChange, placeholder }) => (
          <div key={label} className={s.formGroup}>
            <label className={s.formLabel}>{label}</label>
            <input
              value={value} onChange={(e) => onChange(e.target.value)} placeholder={placeholder}
              className={s.formInput}
            />
          </div>
        ))}

        <div className={`${s.flexRow} ${s.formGroup}`}>
          <div className={s.flexCol}>
            <label className={s.formLabel}>CPU Count</label>
            <input
              type="number" value={cpuCount} onChange={(e) => setCpuCount(e.target.value)}
              className={s.formInput}
            />
          </div>
          <div className={s.flexCol}>
            <label className={s.formLabel}>Memory (GB)</label>
            <input
              type="number" value={memoryGb} onChange={(e) => setMemoryGb(e.target.value)}
              className={s.formInput}
            />
          </div>
        </div>

        <div className={s.formGroupXl}>
          <label className={s.formLabel}>GPU (optional)</label>
          <input
            value={gpu} onChange={(e) => setGpu(e.target.value)} placeholder="NVIDIA RTX 4090"
            className={s.formInput}
          />
        </div>

        <div className={s.flexRowEnd}>
          <Btn variant="secondary" onClick={onClose}>Cancel</Btn>
          <Btn onClick={handleRegister} disabled={loading || !name || !host}>
            {loading ? 'Registering...' : 'Register Worker'}
          </Btn>
        </div>
      </div>
    </div>
  );
}

/* -- Main Page ---------------------------------------------------------- */

export default function ComputeDashboardPage() {
  usePageTitle('Compute');
  const { regions: regionsArr } = useRegions();
  const {
    jobs, workers, usage, credits, tiers, subscription,
    submitJob, cancelJob, addCredits, configureAutoReload, refetch, loading,
  } = useCompute(10000);

  const [toast, setToast] = useState(null);
  const [jobModalOpen, setJobModalOpen] = useState(false);
  const [workerModalOpen, setWorkerModalOpen] = useState(false);
  const [submitLoading, setSubmitLoading] = useState(false);
  const [creditHours, setCreditHours] = useState(50);
  const [autoReload, setAutoReload] = useState(false);
  const [autoReloadThreshold, setAutoReloadThreshold] = useState(10);
  const [autoReloadAmount, setAutoReloadAmount] = useState(50);

  /* check for success redirect */
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    if (params.get('success') === 'true') {
      setToast({ type: 'success', message: 'Compute subscription updated successfully!' });
      window.history.replaceState({}, '', window.location.pathname);
    }
    if (params.get('credits_added') === 'true') {
      setToast({ type: 'success', message: 'Credits added successfully!' });
      window.history.replaceState({}, '', window.location.pathname);
      refetch();
    }
    if (toast) {
      const t = setTimeout(() => setToast(null), 5000);
      return () => clearTimeout(t);
    }
  }, []);

  useEffect(() => {
    if (toast) {
      const t = setTimeout(() => setToast(null), 5000);
      return () => clearTimeout(t);
    }
  }, [toast]);

  const showToast = (type, message) => setToast({ type, message });

  const handleSubmitJob = async (jobType, params, workerType) => {
    setSubmitLoading(true);
    try {
      await submitJob(jobType, params, workerType);
      showToast('success', 'Job submitted successfully!');
      setJobModalOpen(false);
    } catch (err) {
      showToast('error', err.message);
    } finally {
      setSubmitLoading(false);
    }
  };

  const handleCancelJob = async (jobId) => {
    try {
      await cancelJob(jobId);
      showToast('success', 'Job canceled.');
    } catch (err) {
      showToast('error', err.message);
    }
  };

  const handleAddCredits = async () => {
    try {
      const result = await addCredits(creditHours);
      if (result.checkout_url) {
        window.location.href = result.checkout_url;
      }
    } catch (err) {
      showToast('error', err.message);
    }
  };

  const handleWorkerRegistered = (data) => {
    showToast('success', `Worker "${data.worker?.worker_name}" registered!`);
    setWorkerModalOpen(false);
    refetch();
  };

  const handleSaveAutoReload = async () => {
    try {
      await configureAutoReload(autoReload, autoReloadThreshold, autoReloadAmount);
      showToast('success', autoReload ? 'Auto-reload configured.' : 'Auto-reload disabled.');
    } catch (err) {
      showToast('error', err.message);
    }
  };

  const handleDeregisterWorker = async (workerId) => {
    try {
      const res = await fetch(`${getApiBase()}/compute/workers/${workerId}`, {
        method: 'DELETE', headers: authHeaders(),
      });
      if (res.ok) {
        showToast('success', 'Worker removed.');
        refetch();
      }
    } catch (err) {
      showToast('error', err.message);
    }
  };

  /* derived */
  const sub = subscription || {};
  const budget = usage?.budget || {};
  const creditBal = credits?.credits_balance ?? 0;
  const pricePerHr = credits?.price_per_hour ?? 2;
  const monthlyLimit = budget.monthly_limit || sub.compute_hours_limit || 0;
  const monthlyUsed = budget.monthly_used || sub.compute_hours_used || 0;
  const monthlyPct = monthlyLimit > 0 ? pct(monthlyUsed, monthlyLimit) : 0;
  const isUnlimited = monthlyLimit === -1;
  const tierKey = sub.tier || 'local';
  const tierLabel = sub.tier_label || 'Local';
  const tierDef = tiers.find(t => t.key === tierKey) || {};
  const price = tierDef.price_monthly || 0;

  if (loading) {
    return (
      <div className={s.pageRoot}>
        <div className={s.loadingWrap}>
          <div className={s.loadingText}>Loading compute dashboard...</div>
        </div>
      </div>
    );
  }

  return (
    <div className={s.pageRoot}>
      <Toast toast={toast} />
      <SubmitJobModal
        open={jobModalOpen} onClose={() => setJobModalOpen(false)}
        onSubmit={handleSubmitJob} loading={submitLoading}
        regions={regionsArr}
      />
      <RegisterWorkerModal
        open={workerModalOpen} onClose={() => setWorkerModalOpen(false)}
        onRegister={handleWorkerRegistered}
      />

      {/* Header */}
      <div className={s.header}>
        <div>
          <div className={s.headerLeft}>
            <AuraLogo variant="icon" height={48} glow />
            <h1 className={s.headerTitle}>Compute Dashboard</h1>
          </div>
          <p className={s.headerSub}>
            Manage compute jobs, workers, and credits
          </p>
        </div>
        <Btn variant="green" onClick={() => setJobModalOpen(true)}>
          + Submit Job
        </Btn>
      </div>

      {/* Row 1: Subscription + Budget */}
      <div className={s.row}>
        {/* Subscription Card */}
        <Card style={{ flex: '1 1 280px', minWidth: 260 }}>
          <SectionHeader>Subscription</SectionHeader>
          <div className={s.subRow}>
            <TierBadge tier={tierKey} />
            <StatusBadge status={sub.status || 'active'} />
          </div>
          <div className={s.subPrice}>
            <span className={s.subPriceValue}>${price}</span>
            <span className={s.subPricePeriod}>/mo</span>
          </div>
          {sub.cancel_at_period_end && (
            <div className={s.cancelNotice} style={{
              background: `${C.amber}15`, border: `1px solid ${C.amber}30`, color: C.amber,
            }}>
              Cancels at end of period
            </div>
          )}
          <div className={s.subActions}>
            <a href="/pricing" className={s.upgradeLink}>
              {tierKey === 'local' ? 'Upgrade' : 'Manage'}
            </a>
          </div>
        </Card>

        {/* Budget Card */}
        <Card style={{ flex: '2 1 380px', minWidth: 320 }}>
          <SectionHeader>Compute Budget</SectionHeader>

          {/* Monthly allocation bar */}
          <div style={{ marginBottom: 16 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
              <span className={s.budgetLabel}>Monthly Allocation</span>
              <span className={s.budgetValue}>
                {isUnlimited ? 'Unlimited' : `${monthlyUsed.toFixed(1)} / ${monthlyLimit} hrs`}
              </span>
            </div>
            {!isUnlimited && (
              <>
                <div className={s.progressTrack}>
                  <div className={s.progressFill} style={{
                    width: `${monthlyPct}%`,
                    background: barColor(monthlyPct),
                  }} />
                </div>
                <div className={s.pctLabel}>
                  {monthlyPct.toFixed(0)}% used
                </div>
              </>
            )}
          </div>

          {/* Credits balance */}
          <div className={s.creditsBox}>
            <div>
              <div className={s.creditsLabel}>Credits Balance</div>
              <div className={s.creditsValue}>{creditBal.toFixed(1)} hrs</div>
            </div>
            <Btn variant="ghost" onClick={() => {
              document.getElementById('add-funds-section')?.scrollIntoView({ behavior: 'smooth' });
            }}>
              + Add Funds
            </Btn>
          </div>
        </Card>
      </div>

      {/* Row 2: Active Jobs */}
      <Card className={s.cardMb} style={{ marginBottom: 24 }}>
        <div className={s.jobsHeader}>
          <SectionHeader>Jobs</SectionHeader>
          <span className={s.jobsCount}>{jobs.length} total</span>
        </div>

        {jobs.length === 0 ? (
          <div className={s.emptyState}>
            <div className={s.emptyIcon}>&#9881;</div>
            <div className={s.emptyText}>No compute jobs yet</div>
            <Btn variant="ghost" onClick={() => setJobModalOpen(true)}>Submit your first job</Btn>
          </div>
        ) : (
          <div className={s.tableWrap}>
            <table className={s.table}>
              <thead>
                <tr className={s.tableHeadRow}>
                  {['Type', 'Worker', 'Status', 'Submitted', 'Hours', 'Actions'].map((h) => (
                    <th key={h} className={s.th}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {jobs.slice(0, 20).map((job) => (
                  <tr key={job.id} className={s.jobRow}>
                    <td className={s.tdType}>
                      {(job.job_type || '').replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())}
                    </td>
                    <td className={s.tdMono}>{job.worker_type || '--'}</td>
                    <td className={s.td}><StatusBadge status={job.status} /></td>
                    <td className={s.tdMono}>{relTime(job.submitted_at)}</td>
                    <td className={s.tdMonoPrimary}>
                      {job.compute_hours ? `${job.compute_hours.toFixed(1)}h` : '--'}
                    </td>
                    <td className={s.td}>
                      {job.status === 'queued' && (
                        <Btn variant="danger" style={{ padding: '4px 10px', fontSize: 11 }}
                          onClick={() => handleCancelJob(job.id)}>
                          Cancel
                        </Btn>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </Card>

      {/* Row 3: Workers */}
      <Card style={{ marginBottom: 24 }}>
        <div className={s.workersHeader}>
          <SectionHeader>Workers</SectionHeader>
          <Btn variant="ghost" onClick={() => setWorkerModalOpen(true)}>+ Register Local Worker</Btn>
        </div>

        {workers.length === 0 ? (
          <div className={s.emptyWorkers}>No workers registered</div>
        ) : (
          <div className={s.workersList}>
            {workers.map((w) => (
              <div key={w.id} className={s.workerItem}>
                <div className={s.workerLeft}>
                  <span className={s.workerDot} style={{
                    background: STATUS_COLORS[w.status] || C.textSecondary,
                    boxShadow: w.status === 'online' ? `0 0 6px ${C.green}` : 'none',
                  }} />
                  <div style={{ minWidth: 0 }}>
                    <div className={s.workerName}>{w.worker_name}</div>
                    <div className={s.workerSpecs}>
                      {w.cpu_count} CPU &middot; {w.memory_gb}GB
                      {w.gpu ? ` \u00B7 ${w.gpu}` : ''}
                    </div>
                  </div>
                </div>
                <div className={s.workerRight}>
                  <StatusBadge status={w.status} />
                  <span className={s.workerTime}>{relTime(w.last_heartbeat)}</span>
                  <Btn variant="danger" style={{ padding: '4px 8px', fontSize: 10 }}
                    onClick={() => handleDeregisterWorker(w.id)}>
                    Remove
                  </Btn>
                </div>
              </div>
            ))}
          </div>
        )}
      </Card>

      {/* Row 4: Add Funds / Credits */}
      <Card style={{ marginBottom: 24 }} id="add-funds-section">
        <SectionHeader>Add Funds</SectionHeader>

        <div className={s.fundsRow}>
          {/* Purchase credits */}
          <div className={s.fundsCol}>
            <div className={s.fundsTitle}>Buy Compute Credits</div>
            <div className={s.fundsSub}>${pricePerHr}/hr &mdash; credits never expire</div>

            <div className={s.formGroup}>
              <label className={s.formLabel}>Amount (hours)</label>
              <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                <input
                  type="number" min={1} max={10000} value={creditHours}
                  onChange={(e) => setCreditHours(Math.max(1, parseInt(e.target.value) || 1))}
                  className={s.creditInput}
                />
                <span className={s.creditHoursLabel}>hours</span>
                <span className={s.creditTotal}>
                  = <span className={s.creditTotalGreen}>
                    ${(creditHours * pricePerHr).toFixed(0)}
                  </span>
                </span>
              </div>
            </div>

            {/* Quick amount buttons */}
            <div className={s.quickAmounts}>
              {[10, 25, 50, 100, 250].map((h) => (
                <button key={h} onClick={() => setCreditHours(h)} className={s.quickBtn} style={{
                  background: creditHours === h ? C.blue : C.surface2,
                  color: creditHours === h ? C.bg : C.textSecondary,
                  border: `1px solid ${creditHours === h ? C.blue : C.border}`,
                }}>
                  {h} hrs
                </button>
              ))}
            </div>

            <Btn onClick={handleAddCredits} style={{ width: '100%' }}>
              Purchase {creditHours} hrs for ${(creditHours * pricePerHr).toFixed(0)}
            </Btn>
          </div>

          {/* Auto-reload config */}
          <div className={s.fundsColNarrow}>
            <div className={s.fundsTitle}>Auto-Reload</div>
            <div className={s.fundsSub}>
              Automatically top up when balance drops below a threshold
            </div>

            <label className={s.checkboxLabel}>
              <input
                type="checkbox" checked={autoReload}
                onChange={(e) => setAutoReload(e.target.checked)}
                className={s.checkboxInput}
              />
              Enable auto-reload
            </label>

            {autoReload && (
              <>
                <div className={`${s.flexRow} ${s.formGroup}`}>
                  <div className={s.flexCol}>
                    <label className={s.formLabelSm}>When below (hrs)</label>
                    <input
                      type="number" value={autoReloadThreshold}
                      onChange={(e) => setAutoReloadThreshold(parseInt(e.target.value) || 0)}
                      className={s.formInputSm}
                    />
                  </div>
                  <div className={s.flexCol}>
                    <label className={s.formLabelSm}>Reload (hrs)</label>
                    <input
                      type="number" value={autoReloadAmount}
                      onChange={(e) => setAutoReloadAmount(parseInt(e.target.value) || 0)}
                      className={s.formInputSm}
                    />
                  </div>
                </div>
                <div className={s.autoChargeNote}>
                  Auto-charge ${(autoReloadAmount * pricePerHr).toFixed(0)} when balance &lt; {autoReloadThreshold} hrs
                </div>
              </>
            )}

            <Btn variant="secondary" onClick={handleSaveAutoReload} style={{ marginTop: 8 }}>
              {autoReload ? 'Save Auto-Reload' : 'Save Settings'}
            </Btn>
          </div>
        </div>
      </Card>

      {/* Footer */}
      <div className={s.footer}>
        <span>{jobs.length} jobs &middot; {workers.length} workers</span>
        <span>
          {monthlyLimit > 0 && !isUnlimited
            ? `${monthlyUsed.toFixed(1)}/${monthlyLimit} monthly hrs`
            : isUnlimited ? 'Unlimited compute' : 'Local-only compute'}
          {creditBal > 0 ? ` + ${creditBal.toFixed(1)} credit hrs` : ''}
        </span>
      </div>
    </div>
  );
}
